/*!40000 ALTER TABLE `cases` DISABLE KEYS */;
INSERT INTO `cases` VALUES (1,1,1,'ISO and GDPR','GDPR (Europe)','This case study defines how well the GDPR is aligned with the ISO/IEC 27701:2025 standard. This serves as a baseline for the study.',3,3,3,1),(2,1,2,'ISO and Law 7593/25','Law 7593/25 (Paraguay)','This case study establishes the mapping between the ISO/IEC 27701:2025 and the Law 7593/25 of Paraguay, in order to unveil how well this privacy legal framework is aligned with the standard.',3,3,3,1),(3,1,3,'ISO and Law 21719','Law 21719 (Chile)','This study defines how well the ISO/IEC 27701:2019 standard is aligned with Law 21719 of Chile, allowing to unveils critical maps.',3,3,3,1),(4,1,4,'ISO and LOPDP','LOPDP (Ecuador)','This case study is oriented to establish how well the LOPDP of Ecuador is aligned with the ISO/IEC 27701:2025 standard.',3,3,3,1),(5,1,5,'ISO and RLOPDP','RLOPDP (Ecuador)','In order to determine how well thr RLOPDP of Ecuador is aligned with ISO/IEC 27701:2019, this case study analyzes this regulation through GPT.',3,3,3,1),(6,1,6,'ISO and LFPDPPP','LFPDPPP (México)','This case study analyzes the alignment between the ISO/IEC 27701:2025 and the LFPDPPP, in order to unveil critical gaps that this privacy legal framework could have.',3,3,3,1),(7,1,7,'ISO and LOPDPPSO','LOPDPPSO (México)','This case study analyzes the level of alignment between the ISO/IEC 27701:2025 and LGPDPPSO, in order to be analyzed with GPT some pros and cons.',3,3,3,1),(8,1,8,'ISO and Law 1581','Law 1581 (Colombia)','This case study maps the ISO/IEC 27701:2025 and the Law 1581 of Colombia, in order to analyze current gaps and opportunities for improvement.',3,3,3,1),(9,1,9,'ISO and Decree 1733','Decree 1377 (Colombia)','This case study maps the ISO/IEC 27701:2025 and the Decree 1377 of Colombia, in order to analyze current gaps and opportunities for improvement.',3,3,3,1),(10,1,10,'ISO and Law 29733','Law 29733 (Perú)','Mapping between the ISO/IEC 27701 and the Law 29733 of Perú for analysis purposes.',3,3,3,1),(11,1,11,'ISO and Supreme Decree 016-2024-JUS','Supreme Decree 016-2024-JUS (Perú)','Case study for analyzing the ISO/IEC 27701:2025 and Supreme Decree 016-2024-JUS of Perú.',3,3,3,1),(12,1,12,'ISO and Law 18332','Law 18332 (Uruguay)','Manages the mapping between ISO and Uruguay Law 18332 for subsequent analysis.',3,3,3,1),(13,1,13,'ISO and Law 25316','Law 25316 (Argentina)','Manages the information between ISO/IEC 27701:2025 and Law 25316 from Argentina.',3,3,3,1),(14,1,14,'ISO and LGPD - Law 173709','LGPD - Law 173709 (Brazil)','Mapping of LGPD - Law 173709 fro analysis with ISO/IEC 27701:2025.',3,3,3,1),(15,1,15,'ISO and CCPA','CCPA (California)','Analysis of CCPA under the ISO/IEC 27701:2025 lens.',3,3,3,1);
/*!40000 ALTER TABLE `cases` ENABLE KEYS */;
UNLOCK TABLES;

