/*!40000 ALTER TABLE `laws` DISABLE KEYS */;
INSERT INTO `laws` VALUES (1,'General Data Protection Regulation','GDPR','The GDPR (General Data Protection Regulation) is a European Union regulation designed to protect individuals’ personal data. It sets rules for how organizations collect, process, store, and share personal information, and gives people greater control over their privacy and data rights.',1),(2,'Law 7593/25 Paraguay','Law 7593 25','Law 7593/25 (Paraguay) is Paraguay’s new Personal Data Protection Law, enacted on 27 November 2025, that establishes the country’s first modern, comprehensive legal framework for how personal data must be handled by public and private organizations.',1),(3,'Law 21719 Chile','Law 21719','Law 21719 (Chile) is Chile’s new Personal Data Protection Law (officially Law 21.719), published on December 13, 2024, that regulates how personal data is collected, processed, stored, and shared by public and private organizations and creates the Personal Data Protection Agency as an independent authority to supervise compliance.',1),(4,'Ley Orgánica de Protección de Datos Personales','LOPDP','The Ley Orgánica de Protección de Datos Personales, enacted in May 2021, regulates the collection and use of personal data, protects individuals’ privacy rights, and sets obligations for organizations that process such data.',1),(5,'Reglamento a la Ley Orgánica de Protección de Datos Personales','RLOPDP','The Reglamento a la Ley Orgánica de Protección de Datos Personales de Ecuador (RLOPDP) is the implementing regulation that details and clarifies how the LOPDP must be applied, specifying procedures and obligations.',1),(6,'Ley Federal de Protección de Datos Personales en Posesión de Particulares','LFPDPPP','The LFPDPPP is Mexico’s main data protection law, regulating how private organizations collect, use, store, and protect personal data, and granting individuals rights over their personal information.',1),(7,'Ley General de Protección de Datos Personales en Posesión de Sujetos Obligados','LGPDPPSO','The LGPDPPSO is Mexico’s data protection law that regulates how public authorities and government entities process and protect personal data, ensuring individuals’ privacy rights.',1),(8,'Law 1581 Colombia','Law 1581','Law 1581 of Colombia is the country’s personal data protection law that regulates how personal data is collected, used, stored, and shared, and guarantees individuals’ rights over their personal information, such as access, correction, and deletion.',1),(9,'Decree 1377 Colombia','Decree 1377','Decree 1377 of Colombia is a regulatory decree that implements Law 1581, establishing procedures and requirements for the authorization, processing, and protection of personal data by organizations.',1),(10,'Law 29733 Perú','Law 29733','Law 29733 of Perú is the Personal Data Protection Law that regulates the collection, processing, and protection of personal data, and guarantees individuals’ rights over their personal information.',1),(11,'Supreme Decree 016-2024-JUS Perú','Supreme Decree 016-2024-JUS','Supreme Decree 016‑2024‑JUS (Peru) is the regulation that implements Law 29733, the Personal Data Protection Law in Peru. Published on November 30 2024 and in force from March 31 2025, it updates and replaces the previous regulation, modernizing the data protection framework.',1),(12,'Law 18331 Uruguay','Law 18331','Law No. 18.331 is Uruguay’s main data protection law, enacted in 2008.\n\nIt regulates the protection of personal data and the right to habeas data, recognizing personal data protection as a fundamental human right.',1),(13,'Law 25326 Argentina','Law 25326','Law No. 25.326 is Argentina’s national Personal Data Protection Law, enacted in 2000. It establishes a legal framework to protect the privacy and personal data of individuals and to guarantee related constitutional rights such as access to personal information and habeas data.',1),(14,'Brazilian Data Protection Law','LGPD - Law 13709','Brazil’s General Data Protection Law (LGPD) (Lei nº 13709 of 2018) is Brazil’s comprehensive data protection and privacy law, similar in purpose to the GDPR in the European Union. It was enacted in 2018 and fully came into force in 2020–2021.',1),(15,'California Consumer Privacy Act ','CCPA','California Consumer Privacy Act (CCPA) is a California state privacy law enacted in 2018 and effective since January 1, 2020.',1);
/*!40000 ALTER TABLE `laws` ENABLE KEYS */;
